const input = $input.first().json;
const destinationAddress = input.destination_address || '';
const arrivalTime = input.arrival_time || '';
const startStationId = input.start_station_id || '60201280';

if (!destinationAddress) {
  return [{ json: { error: 'No destination address provided' } }];
}

if (!arrivalTime) {
  return [{ json: { error: 'No arrival time provided' } }];
}

// Step 1: Convert address to coordinates using Vienna OGD Address Service
let coordinates;
try {
  const geoData = await helpers.httpRequest({
    method: 'GET',
    url: 'https://data.wien.gv.at/daten/OGDAddressService.svc/GetAddressInfo?Address=' + encodeURIComponent(destinationAddress) + '&crs=EPSG:4326'
  });
  if (!geoData.features || geoData.features.length === 0) {
    return [{ json: { error: 'Could not find coordinates for address: ' + destinationAddress } }];
  }

  coordinates = geoData.features[0].geometry.coordinates;
} catch (e) {
  return [{ json: { error: 'Address lookup failed: ' + e.message } }];
}

// Step 2: Request trip from Wiener Linien routing API
let tripData;
let time = arrivalTime;
if (time.includes('T')) {
  time = time.split('T')[1].substring(0, 5);
}
try {
const params = 'type_origin=stopID'
  + '&name_origin=' + encodeURIComponent(startStationId)
  + '&type_destination=coord'
  + '&name_destination=' + encodeURIComponent(coordinates[0] + ':' + coordinates[1] + ':WGS84[DD.ddddd]')
  + '&outputFormat=JSON'
  + '&itdTripDateTimeDepArr=arr'
  + '&itdTime=' + encodeURIComponent(time);
  tripData = await helpers.httpRequest({
    method: 'GET',
    url: 'https://www.wienerlinien.at/ogd_routing/XML_TRIP_REQUEST2?' + params.toString()
  });
} catch (e) {
  return [{ json: { error: 'Wiener Linien routing API error: ' + e.message } }];
}

// Step 3: Extract and sort trips by duration
const trips = tripData.trips || [];
if (trips.length === 0) {
  return [{ json: { error: 'No routes found for this trip' } }];
}

trips.sort((a, b) => {
  const durationA = parseInt(a.duration) || 9999;
  const durationB = parseInt(b.duration) || 9999;
  return durationA - durationB;
});

// Step 4: Return the best trip (shortest duration)
const best = trips[0];
return [{ json: {
  duration: best.duration,
  line_changes: best.interchange,
  total_trips_found: trips.length
} }];
